const Q_CHEMISTRY_2013=[{"id": "objective>Chemistry>2013>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which subject is this?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Biology</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Physics</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Agiculture</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Chemistry</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The subject of these questions is Chemistry. This can be determined from the context of the questions, which all relate to concepts in Chemistry, and from the 'id' field of each question, which includes the term 'Chemistry'.</div>", "topic": "CHEMISTRY"}, {"id": "objective>Chemistry>2013>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of an impurity in a substance will cause the melting point to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increase</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be stable</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be zero</div>", "<div style=\"font-family:Cambria;font-size:17px;\">reduce</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The presence of an impurity in a substance will cause the melting point to reduce. This is because impurities disrupt the regular arrangement of particles in a substance, which weakens the forces holding the particles together and allows the substance to melt at a lower temperature.</div>", "topic": "SEPARATION OF MIXTURES AND PURIFICATION OF CHEMICAL : PURE AND IMPURE SUBSTANCES"}, {"id": "objective>Chemistry>2013>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">What volume of carbon (II) oxide is produced by reacting excess carbon with 10dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of oxygen?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">15dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">10dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">5dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">20dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> <br/>  Equation of the reaction <br/>  <br/>  2C + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>→   2CO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> <br/>  <br/>  Applying Gay - Lussac's law of Combining volume  <br/>  <br/>  Number of moles directly proportional to the volume  <br/>  <br/>  2 : 1 → 2  <br/>  <br/>  (10(1) → 2(10) <br/>  <br/> 10dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> → 20dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>  <br/>  <br/>  Hence, 20dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of CO will be needed </div>", "topic": "CHEMICAL COMBINATION : STOICHIOMETRY"}, {"id": "objective>Chemistry>2013>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  From the diagram above, an ideal gas is represented by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">X</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Y</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Z</div>", "<div style=\"font-family:Cambria;font-size:17px;\">W.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The curve Z represents an ideal gas. The compressibility factor (PV/P) of an ideal gas is unity. The plot PV against P gives a straight line which is parallel to the P-axis.</div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : AN OUTLINE OF THE KINETIC THEORY OF MATTER"}, {"id": "objective>Chemistry>2013>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The rate of diffusion of gas Y is twice that of Z. if the relative molecular mass of Y is 64 and the two gases diffuse under the same conditions, find the relative molecular mass of Z.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">8</div>", "<div style=\"font-family:Cambria;font-size:17px;\">16</div>", "<div style=\"font-family:Cambria;font-size:17px;\">32</div>", "<div style=\"font-family:Cambria;font-size:17px;\">256</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Using graham's law of diffusion <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span><hr size=\"1\" />R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">√</td><td style=\"text-align:center;\">Mm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span><hr size=\"1\" />Mm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span></td></tr></table></div> <br/> y=2Z <br/> R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> = 2Z, R<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = z , Mm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">y</span> = 64, Mm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span> = ? <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2z<hr size=\"1\" />z</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">√</td><td style=\"text-align:center;\">Mm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span><hr size=\"1\" />64</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2<hr size=\"1\" />1</td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\">√</td><td style=\"text-align:center;\">Mm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span><hr size=\"1\" />64</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">2<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span><hr size=\"1\" />1<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span></td><td style=\"text-align:center;\">=</td><td style=\"text-align:center;\"></td><td style=\"text-align:center;\">Mm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span><hr size=\"1\" />64</td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"text-align:center;\">4=</td><td style=\"text-align:center;\">Mm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span><hr size=\"1\" />64</td></tr></table></div> <br/> Mm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span>= 64 x  4 <br/> Mm<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">z</span> = 256 <br/> </div>", "topic": "KINETIC THEORY OF MATTER AND GAS LAWS : THE LAWS OF BOYLE, CHARLES, GRAHAM AND DALTON LAW OF PARTIAL PRESSURE"}, {"id": "objective>Chemistry>2013>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The radioisotope used in industrial radiography for the rapid checking of faults in welds and casting is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">cobalt-60</div>", "<div style=\"font-family:Cambria;font-size:17px;\">iodine-131</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon-14</div>", "<div style=\"font-family:Cambria;font-size:17px;\">phosphorus-32</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cobalt-60 is a common radioisotope used in industrial radiography. It emits gamma rays which can penetrate materials and reveal structural faults in welds and castings. The other isotopes listed are used in other applications, such as medical treatments and dating of archaeological samples.</div>", "topic": "NUCLEAR CHEMISTRY : RADIOACTIVITY"}, {"id": "objective>Chemistry>2013>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">How many unpaired electrons are in the P-orbitals of a fluorine atom?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">1</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">F = 2, 7: 1S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span>, 2S<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2P<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">5</span>; hence, it is just one unpaired e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> in a Fluorine atom.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2013>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The radioactive emission with the least ionization power is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">γ-rays</div>", "<div style=\"font-family:Cambria;font-size:17px;\">β-particles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">α-particles</div>", "<div style=\"font-family:Cambria;font-size:17px;\">X-rays</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gamma rays (γ-rays) have the least ionizing power among the listed radioactive emissions. This is because they are uncharged and have high energy, allowing them to pass through matter without causing significant ionization. Alpha particles (α-particles) and beta particles (β-particles) are charged and therefore have higher ionizing power.</div>", "topic": "NUCLEAR CHEMISTRY : RADIOACTIVITY"}, {"id": "objective>Chemistry>2013>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The shape of the carbon(IV)oxide molecule is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">angular</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tetrahedral</div>", "<div style=\"font-family:Cambria;font-size:17px;\">pyramidal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">linear</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The shape of the carbon(IV)oxide molecule (CO2) is linear. This is because the carbon atom forms two double bonds with two oxygen atoms, and these bonds are arranged in a straight line to minimize electron repulsion.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : SHAPES OF SIMPLE MOLECULES"}, {"id": "objective>Chemistry>2013>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following molecules is held together by hydrogen bond?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HF</div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HBr</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Hydrogen bonding is a special type of dipole-dipole attraction between molecules, when a hydrogen atom bonded to a strongly electronegative atom exists in the vicinity of another electronegative atom with a lone pair of electrons. HF (Hydrogen Fluoride) is held together by hydrogen bonds. The hydrogen atom is bonded to a highly electronegative fluorine atom, which allows for this type of interaction.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2013>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The bond formed between two elements with electron configurations 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">6</span> 3s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> and 1s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2s<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2</span> 2p<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span> is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">dative</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">metallic</div>", "<div style=\"font-family:Cambria;font-size:17px;\">covalent</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The bond formed between the two elements is ionic.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : CHEMICAL BONDING"}, {"id": "objective>Chemistry>2013>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The constituent of air that acts as a diluent is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">noble gases</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">nitrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">carbon (IV) oxide</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In air, Nitrogen is the most abundant gas, making up about 78% of the Earth's air. It is a diluent that reduces the concentration of oxygen and prevents spontaneous combustion.</div>", "topic": "AIR : GASEOUS CONSTITUENTS"}, {"id": "objective>Chemistry>2013>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Steam changes the colour of anhydrous cobalt (II) chloride from</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">blue to pink</div>", "<div style=\"font-family:Cambria;font-size:17px;\">white to blue</div>", "<div style=\"font-family:Cambria;font-size:17px;\">white to red</div>", "<div style=\"font-family:Cambria;font-size:17px;\">blue to white</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cobalt chloride, CoCl2, is a fascinating compound that changes color in response to humidity. As humidity increases, cobalt chloride changes color from sky blue to purple to pink.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2013>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a hygroscopic substance is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CaCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NaOH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CuO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">MgCl<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(s)</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An example of a hygroscopic substance is CuO. Hygroscopy is the ability of a substance to attract and hold water molecules from the surrounding environment.  <br/> This is achieved through either absorption or absorption with the absorbing or adsorbing substance becoming physically changed somewhat.</div>", "topic": "WATER : WATER OF CRYSTALLIZATION EFFLORESENCE DELIQUESCENCE AND HYGROSCOPY"}, {"id": "objective>Chemistry>2013>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If 24.4g of lead (II) trioxonitrate(V) were dissolved in 42g of distilled water at 20°C, calculate the solubility of the solute in gdm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">5.810</div>", "<div style=\"font-family:Cambria;font-size:17px;\">58.10</div>", "<div style=\"font-family:Cambria;font-size:17px;\">581.00</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.581</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Solubility in g/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = mass of solute x 1000 / solvent <br/> = 24.4/42 x 1000 <br/> =0.5809524 x 1000 <br/> =581g/dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "SOLUBILITY : UNSATURATED SATURATED AND SUPERSATURATED SOLUTIONS"}, {"id": "objective>Chemistry>2013>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The solvent used for removing grease stain is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">solution of borax in water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">turpentine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ammonia solution</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The solvent used for removing grease stain is ammonia solution</div>", "topic": "SOLUBILITY : SOLVENTS"}, {"id": "objective>Chemistry>2013>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a water body, too much sewage leads to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">an increase in the bacterial population which reduced the level of oxygen in the water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the bacterial population which increases the level of oxygen in the water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">a decrease in the temperature of the water which causes death of aquatic animals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">an increase in the number of aquatic animals in the water</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Too much sewage in water body leads to increase in bacterial population which reduces the level of oxygen in the water. </div>", "topic": "ENVIRONMENTAL POLLUTION : WATER POLLUTION"}, {"id": "objective>Chemistry>2013>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">10.0dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of water was added to 2.0mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> of 2.5dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> solution of HCl. What is the concentration of the final solution in mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span>?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2.0</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.5</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">8.0</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Applying dilution theory  <br/>  <br/>  C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/>  <br/>  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>+ X;  X = volume of water added. <br/>  <br/>  C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2.0moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>; V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = 2.5dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>; C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = ? <br/>  <br/>  V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> + X = 2.5 + 10 = 12.5dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/>  <br/>  C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">1</span> = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>V<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>  <br/>  <br/>  2 x 2.5 = C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> x 12.5  <br/> C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 5/12.5 <br/>  C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> = 0.4moldm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span></div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2013>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Three drops of a 1.0mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> solution of HCl was added to 20cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of a solution of pH 6.4. The pH of the resulting solution will be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">greater than 6.4</div>", "<div style=\"font-family:Cambria;font-size:17px;\">unaltered</div>", "<div style=\"font-family:Cambria;font-size:17px;\">close to that of pure water</div>", "<div style=\"font-family:Cambria;font-size:17px;\">less than 6.4</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The pH of a solution is a measure of its acidity or alkalinity. When an acid is added to a solution, it increases the concentration of hydrogen ions in the solution, thereby lowering the pH. In this case, adding drops of a 1.0mol dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-3</span> solution of HCl to a solution of pH 6.4 will increase the concentration of hydrogen ions in the solution and lower the pH. So, the correct option is 4.</div>", "topic": "ACID BASE AND SALTS : PH AND POH SCALE"}, {"id": "objective>Chemistry>2013>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following substances is not a salt?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sodium trioxocarbonate(IV)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zinc chloride</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sodium hydrogentrioxosulphate (IV)</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A salt is a compound which is formed from the neutralization reaction of acids and bases. Sodium trioxocarbonate(IV), Zinc chloride, and Sodium hydrogentrioxosulphate (IV) are all salts. However, Aluminium oxide is not a salt but an oxide.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2013>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An insoluble salt can be prepared by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the action of dilute acid on an insoluble base</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the reaction of metals with an acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the reaction of trioxocarbonate (IV) with an acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">double decomposition</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An insoluble salt can be prepared by double decomposition. Double decomposition is a type of chemical reaction where two compounds react, and positive ions (cation) and the negative ions (anion) of the two reactants switch places, forming two new compounds. One of these new compounds is usually insoluble in water and precipitates out of the solution, thus forming an insoluble salt.</div>", "topic": "ACID BASE AND SALTS : HYDROLYSIS OF SALTS"}, {"id": "objective>Chemistry>2013>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l) </span>+ 2F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> → 4HF<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>  <br/>  In the reaction above, the substance that is being reduced is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">HF(aq)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>(g)</div>", "<div style=\"font-family:Cambria;font-size:17px;\">H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O(l)</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(l) </span>+ 2F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g) </span>→   4HF<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(aq)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span><span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span>  <br/>  The substance that is being reduced is F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>. This is because the oxidation number of fluorine decreases from 0  (in F<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>) to  -1 (in HF).</div>", "topic": "OXIDATION AND REDUCTION : REDUCTION"}, {"id": "objective>Chemistry>2013>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> → ZnSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span> + Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span>  <br/>  In the reaction above, the oxidizing agent is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Cu<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">Zn<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">ZnSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In the given reaction, the oxidizing agent is CuSO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(aq)</span>. An oxidizing agent is a substance that has the ability to oxidize other substances, in other words, it accepts their electrons. In the reaction, CuSO4 is reduced to Cu, meaning it gains electrons and thus is the oxidizing agent.</div>", "topic": "OXIDATION AND REDUCTION : OXIDATION"}, {"id": "objective>Chemistry>2013>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an electrochemical cell, polarization is caused by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">tetraoxosulphate(VI) acid</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydrogen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">chlorine</div>", "<div style=\"font-family:Cambria;font-size:17px;\">oxygen</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In an electrochemical cell, polarization is caused by the build-up of hydrogen gas on the surface of the electrode. This build-up can create a barrier between the electrode and the electrolyte, which can reduce the efficiency of the cell.</div>", "topic": "ELECTROLYSIS : ELECTROCHEMICAL CELLS"}, {"id": "objective>Chemistry>2013>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the volume in cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> of oxygen evolved at s.t.p. when a current of 5A is passed through acidified water for 193s.  <br/> [F = 96,500 Cmol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>, Molar volume of a gas at s.t.p. = 22.4 dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span>]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">0.224</div>", "<div style=\"font-family:Cambria;font-size:17px;\">56.000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">224.000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">0.056.</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">This is what happens when oxygen is liberated at the anode <br/> 4e<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> + 2H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> → 4OH<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-</span> <br/> 4F liberates 1 mole of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> Recall: Q = It <br/> Q = 5 × 193 = 965C <br/> N.B 1F = 96,500C <br/> x = 965C <br/> x = 0.01F <br/> From what we above: <br/> 4F ≡ 1 mole of O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> <br/> 0.01F ≡ x <br/> 4x = 0.01mole <br/> x = 0.01/4 mole <br/> NOTE: 1 mole of any gas at s.t.p is equivalent to 22.4dm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> = 22,400cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span> <br/> ∴ 0.0025mole will occupy, 0.0025 × 22,400= 56cm<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">3</span></div>", "topic": "ELECTROLYSIS : FARADAY'S LAW OF ELECTROLYSIS"}, {"id": "objective>Chemistry>2013>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an endothermic reaction, if there is a loss in entropy, the reaction will</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">not be spontaneous</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be at equilibrium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be indeterminate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">be spontaneous</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From ΔG = ΔH – TΔS, since ΔS = - ve    ΔH= +ve  <br/>  G>0, Hence the reaction will not be spontaneous. Assuming values for S, T and G to confirm this.</div>", "topic": "ENERGY CHANGES : ENTROPY"}, {"id": "objective>Chemistry>2013>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span> + O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>⇔ 2SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> ΔH = -395.7kJ mol<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">-1</span>  <br/>  In the reaction above, the concentration of SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> can be increased by</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">increasing the temperature</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the addition of catalyst</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing the pressure</div>", "<div style=\"font-family:Cambria;font-size:17px;\">decreasing the temperature</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The concentration of SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3(g)</span> is increased by decreasing the temperature because the forward reaction is exothermic.</div>", "topic": "CHEMICAL EQUILIBRA : FACTORS GOVERNING THE EQUILIBRIUM POSITION"}, {"id": "objective>Chemistry>2013>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The minimum amount of energy required for a reaction to take place is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">activation energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">kinetic energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">lattice energy</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ionization energy</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The minimum amount of energy required for a reaction to take place is known as the activation energy. It is the energy needed to break the bonds in the reactants and start a chemical reaction.</div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>2013>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  In the graph above, the activation energy of the catalyzed reaction is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">250kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">200kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">100kJ</div>", "<div style=\"font-family:Cambria;font-size:17px;\">300kJ</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the graph, the Activation Energy of the catalyzed reaction is 200 - 100 = 100KJ.</div>", "topic": "RATE OF CHEMICAL REACTION : ACTIVATION ENERGY"}, {"id": "objective>Chemistry>2013>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(s)</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">(g)</span> ⇌ Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4(s)</span> + 4H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2(g)</span>  <br/>  The equilibrium constant K of the reaction above is represented as</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">[H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><hr size=\"1\" />[H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">[Fe]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">2+</span>[H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><hr size=\"1\" />[Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>][H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">[Fe<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>][H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>]<hr size=\"1\" />[Fe][H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O]</div>", "<div style=\"font-family:Cambria;font-size:17px;\">[H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><hr size=\"1\" />[H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span></div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The equilibrium constant is K = [H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span><hr size=\"1\" />[H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O]<span style=\"margin: 0;padding:0;position:relative;top:-6px;font-size:13px;\">4</span></div>", "topic": "CHEMICAL EQUILIBRA : REVERSIBLE REACTIONS"}, {"id": "objective>Chemistry>2013>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds is a neutral oxide?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Sulphur(IV)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon(II)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carbon(IV)oxide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur(VI)oxide</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A neutral oxide is an oxide that neither has acidic nor basic properties. An example of a neutral oxide is Carbon(II)oxide (CO), which does not react with acids or bases and does not turn blue litmus paper red or red litmus paper blue.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : OXYGEN AND SULPHUR"}, {"id": "objective>Chemistry>2013>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In the laboratory preparation of ammonia, the flask is placed in a slanting position so as to</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">enhance the speed of the reaction</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent formation of precipitate</div>", "<div style=\"font-family:Cambria;font-size:17px;\">prevent condensed water from breaking the reaction flask</div>", "<div style=\"font-family:Cambria;font-size:17px;\">enable the proper mixing of the reactants in the flask.</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Preparing ammonia in the laboratory requires that the flask is slanted to prevent condensed water from trickling down to the hotter part of the flask and breaking it.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : NITROGEN"}, {"id": "objective>Chemistry>2013>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following gases is employed as an anaesthesia?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">NO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">N<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>O, also known as Nitrous oxide, is used as an anaesthetic. It is commonly known as 'laughing gas' and is used in surgeries and dental procedures for its analgesic and anaesthetic effects.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : NITROGEN"}, {"id": "objective>Chemistry>2013>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Sulphur (IV) oxide is a strong reducing agent in the presence of water due to the formation of</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">hydrogen sulphide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">trioxosulphate (IV) ion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">hydroxide ion</div>", "<div style=\"font-family:Cambria;font-size:17px;\">sulphur (VI) oxide</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">SO<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span> is a strong reducing agent in presence of water due to the formation of trioxosuphate(IV) ion.</div>", "topic": "NON-METALS AND THEIR COMPOUNDS : OXYGEN AND SULPHUR"}, {"id": "objective>Chemistry>2013>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A metal that forms soluble trioxosulphate (IV) salt is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">manganese</div>", "<div style=\"font-family:Cambria;font-size:17px;\">aluminium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">barium</div>", "<div style=\"font-family:Cambria;font-size:17px;\">potassium</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A metal that forms soluble trioxosulphate(IV) salt is potassium. Note that group 1 metal forms soluble salts.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALKALI METALS"}, {"id": "objective>Chemistry>2013>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Copper is displaced from the solution of its salts by most metals because it</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">is a transition element</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has completely filled 3d orbitals</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is at the bottom of the activity series</div>", "<div style=\"font-family:Cambria;font-size:17px;\">is very reactive</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Copper is displaced from the solution of its salts by most metals because it is at the bottom of the activity series.</div>", "topic": "METALS AND THEIR COMPOUNDS : COPPER"}, {"id": "objective>Chemistry>2013>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The coloured nature of transition metal ions are associated with their partially filled</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">p-orbital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">d-orbital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">f-orbital</div>", "<div style=\"font-family:Cambria;font-size:17px;\">s-orbital</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The colored nature of transition metal ions is associated with their partially filled d-orbitals. This is because the d-orbitals of transition metals can absorb certain wavelengths of light, which results in the color we see.</div>", "topic": "ATOMIC STRUCTURE AND BONDING : ATOMIC STRUCTURE ELECTRON CONFIGURATION ATOMIC NUMBER MASS NUMBER AND ISOTOPES"}, {"id": "objective>Chemistry>2013>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium containers are frequently used to transport trioxonitrate (V) acid because aluminium</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">does not corrode</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has a silvery-white appearance</div>", "<div style=\"font-family:Cambria;font-size:17px;\">has a low density</div>", "<div style=\"font-family:Cambria;font-size:17px;\">does not react with the acid</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Aluminium containers are frequently used to transport trioxonitrate (V) acid because aluminium does not react with the acid. Aluminium forms a protective layer of aluminium oxide on its surface which prevents further reaction with the acid.</div>", "topic": "METALS AND THEIR COMPOUNDS : ALUMINIUM"}, {"id": "objective>Chemistry>2013>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">2-methylpropan-2-ol is an example of a</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">secondary alkanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">tertiary alkanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">dihydric alkanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">primary alkanol</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">2-melthylpropan-2-ol is a tertiary alkanol. This is because it has three alkyl groups around the central carbon atom.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2013>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction between ammonia and ethyl ethanoate produces</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">ethanol and propanamide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethanol and ethanamide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">propanol and ethanamide</div>", "<div style=\"font-family:Cambria;font-size:17px;\">propanol and propanamide</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The reaction between ammonia and ethyl ethanoate produces ethanol and ethanamide. This is a typical reaction of amines with esters to form an alcohol and an amide.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>2013>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The decarboxylation of ethanoic acid will produce carbon(IV)oxide and</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">propane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">butane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">methane</div>", "<div style=\"font-family:Cambria;font-size:17px;\">ethane</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The decarboxylation of ethanoic acid will produce carbon(IV)oxide and methane. Decarboxylation is a chemical reaction that removes a carboxyl group and releases carbon dioxide (CO2).</div>", "topic": "ORGANIC COMPOUNDS : ALKANOIC ACIDS"}, {"id": "objective>Chemistry>2013>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The compound above is an</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">alkanal</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanol</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanone</div>", "<div style=\"font-family:Cambria;font-size:17px;\">alkanoate</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The compound is an alkanone because the carbonyl functional group is surrounded by two alkyl groups on both sides.</div>", "topic": "ORGANIC COMPOUNDS : ALKANALS AND ALKANONES"}, {"id": "objective>Chemistry>2013>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The compound that will react with sodium hydroxide to form salt and water only is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH=CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>COOH</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">(CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>)<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>COH</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>COOH is acetic acid, a carboxylic acid. Carboxylic acids react with bases such as sodium hydroxide to form a salt and water, a reaction known as neutralization. The other options are not acids and therefore will not react with sodium hydroxide in the same way.</div>", "topic": "ACID BASE AND SALTS : ACID AND BASE TITRATIONS"}, {"id": "objective>Chemistry>2013>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following compounds in solution will turn red litmus paper blue?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\">R'OR\"</div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\">RNH2</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Amines turn red litmus blue because they are bases.</div>", "topic": "ACID BASE AND SALTS : GENERAL CHARACTERISTICS AND PROPERTIES"}, {"id": "objective>Chemistry>2013>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The dehydration of ammonium salt of alkanoic acids produces a compound with the general formula</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/></div>", "<div style=\"font-family:Cambria;font-size:17px;\">R-NH2</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Dehydration of ammonium salts of alkanoic acids produces <img src=\"2013/capture5.png\" style=\"position:relative;max-width:100%;\"/></div>", "topic": "ORGANIC COMPOUNDS : ALKANOATES"}, {"id": "objective>Chemistry>2013>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following fractions is used as raw material for the cracking process?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Bitumen</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Diesel oils</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Kerosene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Lubricating oils</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Diesel oils, C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">15</span> H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">32</span> are used as raw material for the cracking process.</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2013>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An organic compound with a pleasant smell is likely to have a general formula</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n+1</span>COOC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n+1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n+1</span>COC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n+1</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n+1</span>CHO</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n+1</span>COOH</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The general formula C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n+1</span>COOC<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">n</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2n+1</span> represents an ester. Esters are known for their pleasant smells and are often used in perfumes and flavorings.</div>", "topic": "ORGANIC COMPOUNDS : ALKANOLS"}, {"id": "objective>Chemistry>2013>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A primary amide is generally represented by the formula</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">RCONHR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">RCONR<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">RCOOR</div>", "<div style=\"font-family:Cambria;font-size:17px;\">RCONH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A primary amide is generally represented by the formula RCONH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>. In this formula, 'R' represents an alkyl or aryl group, 'CO' is a carbonyl group, and 'NH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span>' is an amine group. The other options represent different types of organic compounds.</div>", "topic": "ORGANIC COMPOUNDS : AMINES"}, {"id": "objective>Chemistry>2013>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"data:image/png;base64,\" style=\"position:relative;max-width:100%;\"/>  <br/>  The IUPAC nomenclature for the compound above is</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">2-methylpent-1-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">2-methylpent-4-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">4-methylpent-1-ene</div>", "<div style=\"font-family:Cambria;font-size:17px;\">3-methylpent-2-ene</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><img src=\"2013/chem2013d.png\" style=\"position:relative;max-width:100%;\"/>  <br/>  <br/>  The counting that favours the functional group will be considered; that is from right to left  <br/>  <br/>  The longest continous carbon chain is 5 and the functional group -ene-carbon -to- carbon double bond. <br/>  <br/>  Hence the root name is pent-1-ene; 1 because the double bond is on the first carbon.  <br/>  <br/>  The attachment is methyl (CH<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>) located on the 4th carbon  <br/>  <br/>  Thus the compound above is 4-methyl pent-1-ene</div>", "topic": "ORGANIC COMPOUNDS : ALIPHATIC HYDROCARBONS"}, {"id": "objective>Chemistry>2013>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">An organic compound contains 60% carbon, 13.3% hydrogen and 26.7% oxygen. Calculate the empirical formula.  <br/> [C = 12, H = 1, O = 16]</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">6</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">13</span>O<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">2</span></div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">4</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">9</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">5</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">12</span>O</div>", "<div style=\"font-family:Cambria;font-size:17px;\">C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> c</td><td style=\"border:1px solid black;text-align:center;\"> H</td><td style=\"border:1px solid black;text-align:center;\"> O <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">% comp.</td><td style=\"border:1px solid black;text-align:center;\"> 60</td><td style=\"border:1px solid black;text-align:center;\"> 13.3</td><td style=\"border:1px solid black;text-align:center;\"> 26.7 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">mass</td><td style=\"border:1px solid black;text-align:center;\"> 60</td><td style=\"border:1px solid black;text-align:center;\"> 13.3</td><td style=\"border:1px solid black;text-align:center;\"> 26.7 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">number of moles</td><td style=\"border:1px solid black;text-align:center;\"> 60/12 = 5</td><td style=\"border:1px solid black;text-align:center;\"> 13.3/1 = 13.3</td><td style=\"border:1px solid black;text-align:center;\"> 267/16 = 1.7 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 5</td><td style=\"border:1px solid black;text-align:center;\"> 13.3</td><td style=\"border:1px solid black;text-align:center;\"> 1.7 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Divided by the smallest value</td><td style=\"border:1px solid black;text-align:center;\"> 2.9 </td><td style=\"border:1px solid black;text-align:center;\"> 17.8</td><td style=\"border:1px solid black;text-align:center;\"> 1 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> 3</td><td style=\"border:1px solid black;text-align:center;\"> 8</td><td style=\"border:1px solid black;text-align:center;\"> 1</td></tr></table></div> <br/> Hence; C<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">3</span>H<span style=\"margin: 0;padding:0;position:relative;top:4px;font-size:13px;\">8</span>O.</div>", "topic": "CHEMICAL COMBINATION : THE MOLE CONCEPT AND AVOGADRO'S NUMBER"}];
